          "claude-story-verify-rerun-002",
          baseVerifierPayload(fixture)
        ),
      },
    ],
  });

  const sharedEnv = {
    PATH: `${providerBinDir}:${process.env.PATH ?? ""}`,
    ...codexProvider.env,
    ...claudeProvider.env,
